public string ProcessUserInput(string input, bool isAdmin, UserType userType, int accessLevel) // Compliant: simplified logic
{
    if (input == null)
        return "Invalid input";

    return isAdmin ? ProcessAdminUser(userType, accessLevel) : ProcessRegularUser(userType, accessLevel);
}

private string ProcessAdminUser(UserType userType, int accessLevel)
{
    return userType switch
    {
        UserType.SuperAdmin => GetSuperAdminAccess(accessLevel),
        UserType.Admin => GetAdminAccess(accessLevel),
        _ => "Basic admin access"
    };
}

private string ProcessRegularUser(UserType userType, int accessLevel)
{
    return userType == UserType.Premium ? GetPremiumAccess(accessLevel) : "Regular user access";
}
